public double[][][] filterFeaturesByPrediction(double[][][] features, double[] prediction,
                                               double upThreshold, double downThreshold) {
    List<double[][]> filteredFeatures = new ArrayList<>();
    // 遍历预测值
    for (int i = 0; i < prediction.length; i++) {
        if (prediction[i] > upThreshold || prediction[i] < downThreshold) {
            filteredFeatures.add(features[i]); // 符合条件，添加对应的特征集
